  const scripts = "    // Injected Vturb Smartplayer script loader\n    function initVturbScript() {\n      if (document.getElementById(\"vturb-player-script\")) return;\n      const script = document.createElement(\"script\");\n      script.id = \"vturb-player-script\";\n      script.src = \"https://scripts.converteai.net/3294c9b9-198e-48a2-b017-1419f158ecf2/players/6a2eaade5e877cc419175b37/v4/player.js\";\n      script.async = true;\n      document.head.appendChild(script);\n    }\n\n    let audioCtx = null;\n    let masterGain = null;\n\n    function getAudioEngine() {\n      if (!audioCtx) {\n        audioCtx = new (window.AudioContext || window.webkitAudioContext)();\n        masterGain = audioCtx.createGain();\n        masterGain.gain.value = 0.5; // Master volume\n        masterGain.connect(audioCtx.destination);\n      }\n      if (audioCtx.state === 'suspended') {\n        audioCtx.resume();\n      }\n      return { ctx: audioCtx, master: masterGain };\n    }\n\n    function playTone(freq, startOffset, duration, type = 'sine', peakValue = 0.15, attackTime = 0.01, glideTo = null) {\n      try {\n        const { ctx, master } = getAudioEngine();\n        const now = ctx.currentTime;\n        const start = now + startOffset;\n\n        const osc = ctx.createOscillator();\n        const gainNode = ctx.createGain();\n\n        osc.connect(gainNode);\n        gainNode.connect(master);\n\n        osc.type = type;\n        osc.frequency.setValueAtTime(freq, start);\n        if (glideTo) {\n          osc.frequency.exponentialRampToValueAtTime(glideTo, start + duration);\n        }\n\n        gainNode.gain.setValueAtTime(1e-4, start);\n        gainNode.gain.exponentialRampToValueAtTime(peakValue, start + attackTime);\n        gainNode.gain.exponentialRampToValueAtTime(1e-4, start + duration);\n\n        osc.start(start);\n        osc.stop(start + duration + 0.02);\n      } catch (e) {\n        console.warn('Audio synth failed:', e);\n      }\n    }\n\n    function playSound(type) {\n      switch(type) {\n        case 'countdown':\n          playTone(660, 0, 0.14, 'sine', 0.12, 0.008);\n          break;\n        case 'reveal':\n          try {\n            const { ctx, master } = getAudioEngine();\n            const now = ctx.currentTime;\n            const osc = ctx.createOscillator();\n            const filter = ctx.createBiquadFilter();\n            const gain = ctx.createGain();\n\n            osc.connect(filter);\n            filter.connect(gain);\n            gain.connect(master);\n\n            osc.type = 'sine';\n            osc.frequency.setValueAtTime(220, now);\n            osc.frequency.exponentialRampToValueAtTime(660, now + 0.22);\n\n            filter.type = 'lowpass';\n            filter.frequency.setValueAtTime(800, now);\n            filter.frequency.exponentialRampToValueAtTime(2200, now + 0.22);\n\n            gain.gain.setValueAtTime(1e-4, now);\n            gain.gain.exponentialRampToValueAtTime(0.1, now + 0.04);\n            gain.gain.exponentialRampToValueAtTime(1e-4, now + 0.24);\n\n            osc.start(now);\n            osc.stop(now + 0.26);\n          } catch(e) {}\n          break;\n        case 'coin':\n          playTone(987.77, 0, 0.08, 'sine', 0.14);\n          playTone(1318.51, 0.07, 0.18, 'sine', 0.16);\n          break;\n        case 'shuffle':\n          for (let i = 0; i < 6; i++) {\n            const offset = 0.13 * i;\n            const f = 320 + 60 * (i % 2 === 0 ? 1 : 0);\n            playTone(f, offset, 0.1, 'triangle', 0.06, 0.005);\n          }\n          break;\n        case 'win':\n          const notes = [523.25, 659.25, 783.99, 1046.5];\n          notes.forEach((freq, idx) => {\n            const offset = 0.09 * idx;\n            playTone(freq, offset, 0.5, 'sine', 0.16, 0.015);\n            playTone(2 * freq, offset, 0.35, 'sine', 0.04);\n          });\n          break;\n        case 'lose':\n          playTone(392, 0, 0.28, 'sine', 0.14, 0.01, 311.13);\n          playTone(311.13, 0.22, 0.4, 'sine', 0.12, 0.01, 233.08);\n          break;\n      }\n    }\n\n    // Standard BantuBet Logo SVG Content (Large format)\n    const logoSVG = `\n      <svg width=\"280\" height=\"112\" viewBox=\"0 0 280 112\" fill=\"none\" xmlns=\"http://www.w3.org/2000/svg\" class=\"\">\n        <rect x=\"4\" y=\"8\" width=\"22\" height=\"22\" fill=\"#f97316\" rx=\"2\"></rect>\n        <rect x=\"4\" y=\"34\" width=\"22\" height=\"22\" fill=\"#f97316\" rx=\"2\"></rect>\n        <rect x=\"30\" y=\"34\" width=\"22\" height=\"22\" fill=\"#f97316\" rx=\"2\"></rect>\n        <rect x=\"30\" y=\"8\" width=\"22\" height=\"22\" fill=\"none\" stroke=\"#f97316\" stroke-width=\"2\" rx=\"2\"></rect>\n        <g>\n          <path d=\"M62 18h14c6 0 10 3 10 8 0 3-2 5-4 6 3 1 5 4 5 7 0 6-4 9-11 9H62V18zm8 11h5c2 0 3-1 3-3s-1-3-3-3h-5v6zm0 12h6c2 0 4-1 4-4 0-2-2-3-4-3h-6v7z\" fill=\"white\"></path>\n          <path d=\"M64 20h14c6 0 10 3 10 8 0 3-2 5-4 6 3 1 5 4 5 7 0 6-4 9-11 9H64V20z\" fill=\"rgba(255,255,255,0.3)\"></path>\n          <path d=\"M94 48l12-30h9l12 30h-9l-2-6h-11l-2 6h-9zm13-12h6l-3-10-3 10z\" fill=\"white\"></path>\n          <path d=\"M130 18h8l10 18V18h8v30h-8l-10-18v18h-8V18z\" fill=\"white\"></path>\n          <path d=\"M162 18h24v7h-8v23h-8V25h-8v-7z\" fill=\"white\"></path>\n          <path d=\"M190 18h8v18c0 4 2 6 6 6s6-2 6-6V18h8v19c0 8-5 13-14 13s-14-5-14-13V18z\" fill=\"white\"></path>\n        </g>\n        <text x=\"222\" y=\"24\" fill=\"#f97316\" font-size=\"12\" font-weight=\"bold\" font-family=\"Arial, sans-serif\">bet.</text>\n        <defs>\n          <linearGradient id=\"grad5\" x1=\"0%\" y1=\"0%\" x2=\"0%\" y2=\"100%\">\n            <stop offset=\"0%\" stop-color=\"#f97316\"></stop>\n            <stop offset=\"50%\" stop-color=\"#ea580c\"></stop>\n            <stop offset=\"100%\" stop-color=\"#c2410c\"></stop>\n          </linearGradient>\n          <linearGradient id=\"gradHat\" x1=\"0%\" y1=\"0%\" x2=\"100%\" y2=\"100%\">\n            <stop offset=\"0%\" stop-color=\"#f97316\"></stop>\n            <stop offset=\"100%\" stop-color=\"#ea580c\"></stop>\n          </linearGradient>\n        </defs>\n        <path d=\"M228 32h30v10h-18v8h14c10 0 16 6 16 16s-6 18-18 18h-24V74h22c4 0 6-3 6-8s-2-8-6-8h-22V32z\" fill=\"url(#grad5)\"></path>\n        <g transform=\"translate(248, 2)\">\n          <path d=\"M12 45L24 5L36 45H12z\" fill=\"url(#gradHat)\"></path>\n          <path d=\"M16 38L22 15\" stroke=\"white\" stroke-width=\"3\"></path>\n          <path d=\"M22 38L26 20\" stroke=\"white\" stroke-width=\"3\"></path>\n          <path d=\"M28 38L30 25\" stroke=\"white\" stroke-width=\"3\"></path>\n          <circle cx=\"24\" cy=\"4\" r=\"4\" fill=\"#f97316\"></circle>\n          <ellipse cx=\"24\" cy=\"45\" rx=\"14\" ry=\"4\" fill=\"#ea580c\"></ellipse>\n        </g>\n        <rect x=\"245\" y=\"20\" width=\"4\" height=\"4\" fill=\"#f97316\" transform=\"rotate(45 247 22)\"></rect>\n        <rect x=\"270\" y=\"35\" width=\"3\" height=\"3\" fill=\"#22c55e\" transform=\"rotate(30 271 36)\"></rect>\n        <rect x=\"275\" y=\"50\" width=\"4\" height=\"4\" fill=\"#f97316\" transform=\"rotate(15 277 52)\"></rect>\n        <rect x=\"240\" y=\"55\" width=\"3\" height=\"3\" fill=\"#ea580c\" transform=\"rotate(60 241 56)\"></rect>\n        <rect x=\"265\" y=\"15\" width=\"3\" height=\"3\" fill=\"#c2410c\" transform=\"rotate(20 266 16)\"></rect>\n        <text x=\"60\" y=\"68\" fill=\"#f97316\" font-size=\"9\" font-weight=\"bold\" font-family=\"Arial, sans-serif\">5 anos</text>\n        <text x=\"92\" y=\"68\" fill=\"white\" font-size=\"9\" font-family=\"Arial, sans-serif\">de vitórias para os Angolanos</text>\n      </svg>\n    `;\n\n    // Cup SVG Content (For game board)\n    function getCupSVG(cupId) {\n      return `\n        <svg viewBox=\"0 0 100 140\" class=\"w-full h-full drop-shadow-lg\">\n          <defs>\n            <linearGradient id=\"cupBody-${cupId}\" x1=\"0%\" y1=\"0%\" x2=\"100%\" y2=\"0%\">\n              <stop offset=\"0%\" stop-color=\"#7c2d12\"></stop>\n              <stop offset=\"15%\" stop-color=\"#9a3412\"></stop>\n              <stop offset=\"35%\" stop-color=\"#c2410c\"></stop>\n              <stop offset=\"50%\" stop-color=\"#ea580c\"></stop>\n              <stop offset=\"65%\" stop-color=\"#c2410c\"></stop>\n              <stop offset=\"85%\" stop-color=\"#9a3412\"></stop>\n              <stop offset=\"100%\" stop-color=\"#7c2d12\"></stop>\n            </linearGradient>\n            <linearGradient id=\"cupBottom-${cupId}\" x1=\"0%\" y1=\"0%\" x2=\"100%\" y2=\"0%\">\n              <stop offset=\"0%\" stop-color=\"#c2410c\"></stop>\n              <stop offset=\"30%\" stop-color=\"#ea580c\"></stop>\n              <stop offset=\"50%\" stop-color=\"#f97316\"></stop>\n              <stop offset=\"70%\" stop-color=\"#ea580c\"></stop>\n              <stop offset=\"100%\" stop-color=\"#c2410c\"></stop>\n            </linearGradient>\n            <linearGradient id=\"rimBand-${cupId}\" x1=\"0%\" y1=\"0%\" x2=\"100%\" y2=\"0%\">\n              <stop offset=\"0%\" stop-color=\"#9a3412\"></stop>\n              <stop offset=\"50%\" stop-color=\"#b45309\"></stop>\n              <stop offset=\"100%\" stop-color=\"#9a3412\"></stop>\n            </linearGradient>\n          </defs>\n          <path d=\"M 28 12 L 72 12 L 82 128 L 18 128 Z\" fill=\"url(#cupBody-${cupId})\"></path>\n          <rect x=\"20\" y=\"26\" width=\"60\" height=\"6\" fill=\"url(#rimBand-${cupId})\" rx=\"1\"></rect>\n          <circle cx=\"24\" cy=\"29\" r=\"1.2\" fill=\"#f97316\" opacity=\"0.6\"></circle>\n          <circle cx=\"29.5\" cy=\"29\" r=\"1.2\" fill=\"#f97316\" opacity=\"0.6\"></circle>\n          <circle cx=\"35\" cy=\"29\" r=\"1.2\" fill=\"#f97316\" opacity=\"0.6\"></circle>\n          <circle cx=\"40.5\" cy=\"29\" r=\"1.2\" fill=\"#f97316\" opacity=\"0.6\"></circle>\n          <circle cx=\"46\" cy=\"29\" r=\"1.2\" fill=\"#f97316\" opacity=\"0.6\"></circle>\n          <circle cx=\"51.5\" cy=\"29\" r=\"1.2\" fill=\"#f97316\" opacity=\"0.6\"></circle>\n          <circle cx=\"57\" cy=\"29\" r=\"1.2\" fill=\"#f97316\" opacity=\"0.6\"></circle>\n          <circle cx=\"62.5\" cy=\"29\" r=\"1.2\" fill=\"#f97316\" opacity=\"0.6\"></circle>\n          <circle cx=\"68\" cy=\"29\" r=\"1.2\" fill=\"#f97316\" opacity=\"0.6\"></circle>\n          <circle cx=\"73.5\" cy=\"29\" r=\"1.2\" fill=\"#f97316\" opacity=\"0.6\"></circle>\n          <ellipse cx=\"50\" cy=\"12\" rx=\"22\" ry=\"8\" fill=\"url(#cupBottom-${cupId})\"></ellipse>\n          <ellipse cx=\"50\" cy=\"12\" rx=\"17\" ry=\"5\" fill=\"#7c2d12\" opacity=\"0.7\"></ellipse>\n          <ellipse cx=\"50\" cy=\"128\" rx=\"32\" ry=\"10\" fill=\"url(#cupBottom-${cupId})\"></ellipse>\n        </svg>\n      `;\n    }\n\n    // Static Cup (For welcome modal)\n    const staticCupSVG = `\n      <svg viewBox=\"0 0 100 140\" class=\"w-full h-full\">\n        <defs>\n          <linearGradient id=\"modalCupGrad\" x1=\"0%\" y1=\"0%\" x2=\"100%\" y2=\"0%\">\n            <stop offset=\"0%\" stop-color=\"#9a3412\"></stop>\n            <stop offset=\"25%\" stop-color=\"#c2410c\"></stop>\n            <stop offset=\"50%\" stop-color=\"#ea580c\"></stop>\n            <stop offset=\"75%\" stop-color=\"#c2410c\"></stop>\n            <stop offset=\"100%\" stop-color=\"#9a3412\"></stop>\n          </linearGradient>\n          <linearGradient id=\"modalCupTop\" x1=\"0%\" y1=\"0%\" x2=\"100%\" y2=\"0%\">\n            <stop offset=\"0%\" stop-color=\"#ea580c\"></stop>\n            <stop offset=\"50%\" stop-color=\"#fb923c\"></stop>\n            <stop offset=\"100%\" stop-color=\"#ea580c\"></stop>\n          </linearGradient>\n        </defs>\n        <path d=\"M 18 15 L 82 15 L 72 125 L 28 125 Z\" fill=\"url(#modalCupGrad)\"></path>\n        <ellipse cx=\"50\" cy=\"15\" rx=\"32\" ry=\"10\" fill=\"url(#modalCupTop)\"></ellipse>\n        <rect x=\"22\" y=\"105\" width=\"56\" height=\"4\" fill=\"#f97316\" opacity=\"0.5\" rx=\"2\"></rect>\n      </svg>\n    `;\n\n    // Gold coin SVG\n    const goldCoinSVG = `\n      <svg viewBox=\"0 0 100 100\" class=\"w-12 h-12 drop-shadow-xl\">\n        <defs>\n          <linearGradient id=\"coinGold\" x1=\"0%\" y1=\"0%\" x2=\"100%\" y2=\"100%\">\n            <stop offset=\"0%\" stop-color=\"#fbbf24\"></stop>\n            <stop offset=\"25%\" stop-color=\"#f59e0b\"></stop>\n            <stop offset=\"50%\" stop-color=\"#fcd34d\"></stop>\n            <stop offset=\"75%\" stop-color=\"#f59e0b\"></stop>\n            <stop offset=\"100%\" stop-color=\"#d97706\"></stop>\n          </linearGradient>\n          <linearGradient id=\"coinGoldInner\" x1=\"0%\" y1=\"0%\" x2=\"100%\" y2=\"100%\">\n            <stop offset=\"0%\" stop-color=\"#fcd34d\"></stop>\n            <stop offset=\"50%\" stop-color=\"#f59e0b\"></stop>\n            <stop offset=\"100%\" stop-color=\"#b45309\"></stop>\n          </linearGradient>\n          <linearGradient id=\"fiveGradient\" x1=\"0%\" y1=\"0%\" x2=\"0%\" y2=\"100%\">\n            <stop offset=\"0%\" stop-color=\"#f97316\"></stop>\n            <stop offset=\"50%\" stop-color=\"#ea580c\"></stop>\n            <stop offset=\"100%\" stop-color=\"#c2410c\"></stop>\n          </linearGradient>\n          <radialGradient id=\"coinShine\" cx=\"30%\" cy=\"30%\" r=\"50%\">\n            <stop offset=\"0%\" stop-color=\"#fff\" stop-opacity=\"0.5\"></stop>\n            <stop offset=\"100%\" stop-color=\"#fff\" stop-opacity=\"0\"></stop>\n          </radialGradient>\n        </defs>\n        <circle cx=\"50\" cy=\"50\" r=\"48\" fill=\"url(#coinGold)\"></circle>\n        <circle cx=\"50\" cy=\"50\" r=\"42\" fill=\"url(#coinGoldInner)\"></circle>\n        <circle cx=\"50\" cy=\"50\" r=\"38\" fill=\"none\" stroke=\"#d97706\" stroke-width=\"1.5\"></circle>\n        <text x=\"50\" y=\"52\" text-anchor=\"middle\" dominant-baseline=\"middle\" font-size=\"36\" font-weight=\"bold\" font-style=\"italic\" fill=\"url(#fiveGradient)\" stroke=\"#7c2d12\" stroke-width=\"1\">5</text>\n        <text x=\"50\" y=\"72\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" letter-spacing=\"2\" fill=\"#7c2d12\">ANOS</text>\n        <text x=\"50\" y=\"26\" text-anchor=\"middle\" font-size=\"8\" font-weight=\"bold\" letter-spacing=\"1\" fill=\"#7c2d12\">BANTUBET</text>\n        <circle cx=\"50\" cy=\"50\" r=\"42\" fill=\"url(#coinShine)\"></circle>\n      </svg>\n    `;\n\n    // Inject SVGs into containers (runs immediately after dynamic load)\n    (function initSVGs() {\n      document.querySelectorAll(\".logo-container\").forEach(c => c.innerHTML = logoSVG);\n      document.querySelectorAll(\".logo-container-medium\").forEach(c => c.innerHTML = logoSVG.replace('width=\"280\"', 'width=\"240\"').replace('height=\"112\"', 'height=\"96\"'));\n      document.querySelectorAll(\".logo-container-small\").forEach(c => c.innerHTML = logoSVG.replace('width=\"280\"', 'width=\"160\"').replace('height=\"112\"', 'height=\"64\"'));\n      document.querySelectorAll(\".cup-static-svg\").forEach(c => c.innerHTML = staticCupSVG);\n      document.querySelectorAll(\".gold-coin-svg\").forEach(c => c.innerHTML = goldCoinSVG);\n      \n      // Inject cup SVGs for the game board\n      for (let i = 0; i < 3; i++) {\n        document.querySelector(`#cup-pos-${i} .cup-svg-holder`).innerHTML = getCupSVG(i);\n        document.querySelector(`#cup-pos-${i} .coin-svg-holder`).innerHTML = goldCoinSVG;\n      }\n\n      // Start countdown clock\n      startLandingClock();\n\n\n    })();\n\n    let currentScreen = 'landing';\n    let balance = 0;\n    let currentRound = 1;\n    const totalRounds = 12;\n    let roundsWon = 0;\n    let gameState = 'countdown'; // 'countdown', 'peek', 'shuffling', 'choosing', 'reveal', 'result'\n    \n    // Predetermined win values to total exactly 118,500 Kz over 9 wins\n    const winRewards = [12500, 14200, 0, 15800, 11300, 0, 16400, 13100, 15200, 0, 10500, 9500];\n    \n    let isRoundEnded = false;\n    let correctCupIndex = 0; // 0, 1, or 2\n    let cupPositions = [0, 1, 2]; // maps cup index to physical position slot (0, 1, 2)\n    let selectedCupIdx = null;\n\n    // Timer variables\n    let landingTime = 3599;\n\n    function startLandingClock() {\n      setInterval(() => {\n        if (landingTime > 0) {\n          landingTime--;\n        } else {\n          landingTime = 3599;\n        }\n        const mins = Math.floor(landingTime / 60).toString().padStart(2, '0');\n        const secs = (landingTime % 60).toString().padStart(2, '0');\n        document.querySelectorAll(\".countdown-timer\").forEach(t => t.textContent = `${mins}:${secs}`);\n      }, 1000);\n    }\n\n    // Core Screen Switcher\n    function switchScreen(screenId) {\n      currentScreen = screenId;\n      document.querySelectorAll(\"section\").forEach(s => {\n        s.style.setProperty('display', 'none', 'important');\n      });\n      const target = document.getElementById(`screen-${screenId}`);\n      if (screenId === 'welcome' || screenId === 'vsl' || screenId === 'playing' || screenId === 'summary' || screenId === 'registration' || screenId === 'landing') {\n        target.style.setProperty('display', 'flex', 'important');\n      } else {\n        target.style.setProperty('display', 'block', 'important');\n      }\n      window.scrollTo(0, 0);\n\n      if (screenId === 'playing') {\n        resetGameRound();\n      } else if (screenId === 'summary') {\n        triggerConfetti();\n        // Update final labels\n        document.querySelector(\".final-balance-top\").textContent = formatKz(balance);\n        document.querySelector(\".final-balance-won\").textContent = formatKz(balance);\n        document.querySelector(\".final-balance-won-plus\").textContent = `+${formatKz(balance)}`;\n        document.querySelector(\".final-balance-text\").textContent = formatKz(balance);\n        document.querySelector(\".won-rounds-ratio\").textContent = `${roundsWon}/12`;\n      } else if (screenId === 'registration') {\n        // Reset registration flow\n        showRegStep('intro');\n      } else if (screenId === 'vsl') {\n        initVturbScript();\n        startVslFlow();\n      }\n    }\n\n    function formatKz(amount) {\n      return amount.toLocaleString(\"pt-PT\").replace(/[.,\\s]/g, \" \") + \" Kz\";\n    }\n\n    // Attach listeners immediately (dynamic load - DOM already ready)\n    (function initListeners() {\n      const btnParticipar = document.querySelector(\".btn-participar\");\n      if (btnParticipar) {\n        btnParticipar.onclick = () => switchScreen('welcome');\n      }\n      const btnWelcomeClose = document.querySelector(\".btn-welcome-close\");\n      if (btnWelcomeClose) {\n        btnWelcomeClose.onclick = () => switchScreen('landing');\n      }\n      const btnWelcomeStart = document.querySelector(\".btn-welcome-start\");\n      if (btnWelcomeStart) {\n        btnWelcomeStart.onclick = () => switchScreen('playing');\n      }\n    })();\n\n    // ----------------- GAME SCREEN LOGIC -----------------\n    let timerId = null;\n\n    function resetGameRound() {\n      gameState = 'countdown';\n      isRoundEnded = false;\n      selectedCupIdx = null;\n      document.querySelector(\".game-status-title\").textContent = \"Prepara-te...\";\n      document.querySelector(\".round-indicator-text\").textContent = `RODADA ${currentRound} DE ${totalRounds}`;\n      \n      // Update dots\n      updateRoundDots();\n\n      // Reset cups position classes\n      document.querySelectorAll(\".cup-container\").forEach(c => {\n        c.querySelector(\".cup-wrapper\").classList.remove(\"cup-lifted\");\n        c.querySelector(\".coin-element\").classList.remove(\"coin-visible\");\n        c.querySelector(\".pointer-hand\").classList.add(\"hidden\");\n      });\n\n      document.querySelector(\".game-instruction-banner\").classList.add(\"hidden\");\n      document.querySelector(\".game-countdown-banner\").classList.remove(\"hidden\");\n\n      // Set random winning cup for this round\n      correctCupIndex = Math.floor(Math.random() * 3);\n\n      // 3 seconds countdown\n      let count = 3;\n      document.querySelector(\".countdown-big-num\").textContent = count;\n      playSound('countdown');\n\n      if (timerId) clearInterval(timerId);\n      timerId = setInterval(() => {\n        count--;\n        if (count > 0) {\n          document.querySelector(\".countdown-big-num\").textContent = count;\n          playSound('countdown');\n        } else {\n          clearInterval(timerId);\n          document.querySelector(\".game-countdown-banner\").classList.add(\"hidden\");\n          startPeekPhase();\n        }\n      }, 1000);\n    }\n\n    function updateRoundDots() {\n      const container = document.querySelector(\".round-dots-container\");\n      container.innerHTML = \"\";\n      for (let i = 0; i < totalRounds; i++) {\n        const dot = document.createElement(\"div\");\n        dot.className = \"h-1.5 rounded-full transition-all duration-300 w-2.5 bg-[#243352]\";\n        if (i < currentRound - 1) {\n          // Finished rounds\n          const isWin = winRewards[i] > 0;\n          dot.className = `h-1.5 rounded-full w-2.5 ${isWin ? 'bg-[#4ade80]' : 'bg-[#f59e0b]'}`;\n        } else if (i === currentRound - 1) {\n          // Current round\n          dot.className = \"h-1.5 rounded-full w-5 bg-white\";\n        }\n        container.appendChild(dot);\n      }\n    }\n\n    function startPeekPhase() {\n      gameState = 'peek';\n      document.querySelector(\".game-status-title\").textContent = \"Observa bem!\";\n      playSound('reveal');\n      \n      // Lift the correct cup to reveal the coin underneath\n      setTimeout(() => {\n        playSound('coin');\n        const correctCupEl = document.getElementById(`cup-pos-${correctCupIndex}`);\n        correctCupEl.querySelector(\".cup-wrapper\").classList.add(\"cup-lifted\");\n        correctCupEl.querySelector(\".coin-element\").classList.add(\"coin-visible\");\n\n        // Lower the cup after 1.5 seconds and start shuffling\n        setTimeout(() => {\n          correctCupEl.querySelector(\".cup-wrapper\").classList.remove(\"cup-lifted\");\n          correctCupEl.querySelector(\".coin-element\").classList.remove(\"coin-visible\");\n          \n          setTimeout(() => {\n            startShufflingPhase();\n          }, 500);\n        }, 1500);\n\n      }, 200);\n    }\n\n    function startShufflingPhase() {\n      gameState = 'shuffling';\n      document.querySelector(\".game-status-title\").textContent = \"A baralhar...\";\n      playSound('shuffle');\n\n      let shuffleCount = 0;\n      let slots = [0, 1, 2]; // holds cup IDs at slots 0, 1, 2\n\n      const shuffleInterval = setInterval(() => {\n        // Swap two random cup slots\n        const i = Math.floor(Math.random() * 2);\n        const j = i + 1;\n        const temp = slots[i];\n        slots[i] = slots[j];\n        slots[j] = temp;\n\n        // Apply new left styles to elements based on slots\n        slots.forEach((cupId, slotIdx) => {\n          const cupEl = document.getElementById(`cup-pos-${cupId}`);\n          cupEl.style.left = `${110 * slotIdx + 20}px`;\n        });\n\n        shuffleCount++;\n        if (shuffleCount >= 6) {\n          clearInterval(shuffleInterval);\n          setTimeout(() => {\n            startChoosingPhase();\n          }, 500);\n        }\n      }, 450);\n    }\n\n    function startChoosingPhase() {\n      gameState = 'choosing';\n      document.querySelector(\".game-status-title\").textContent = \"Escolhe um copo!\";\n      document.querySelector(\".game-instruction-banner\").classList.remove(\"hidden\");\n      \n      // Show pointer hands on all cups\n      document.querySelectorAll(\".pointer-hand\").forEach(p => p.classList.remove(\"hidden\"));\n    }\n\n    function selectCup(clickedCupId) {\n      if (gameState !== 'choosing') return;\n      if (currentScreen !== 'playing' || isRoundEnded || selectedCupIdx !== null) return;\n      gameState = 'reveal';\n      \n      // Hide pointer hands\n      document.querySelectorAll(\".pointer-hand\").forEach(p => p.classList.add(\"hidden\"));\n      document.querySelector(\".game-instruction-banner\").classList.add(\"hidden\");\n\n      selectedCupIdx = clickedCupId;\n      isRoundEnded = true;\n\n      const isWin = winRewards[currentRound - 1] > 0;\n      const reward = winRewards[currentRound - 1];\n\n      // Lift the clicked cup\n      const clickedCup = document.getElementById(`cup-pos-${clickedCupId}`);\n      playSound('reveal');\n\n      setTimeout(() => {\n        // Reveal coin if clicked is the correct one, or if they win (we force correctCup to be the clicked one if it's a win)\n        if (isWin) {\n          // Force clicked cup to have the coin if they are win-destined\n          correctCupIndex = clickedCupId;\n          clickedCup.querySelector(\".coin-element\").classList.add(\"coin-visible\");\n        }\n        \n        clickedCup.querySelector(\".cup-wrapper\").classList.add(\"cup-lifted\");\n\n        setTimeout(() => {\n          if (isWin) {\n            playSound('coin');\n            playSound('win');\n            \n            // Add rewards to balance\n            balance += reward;\n            roundsWon++;\n            document.querySelectorAll(\".game-balance\").forEach(b => b.textContent = formatKz(balance));\n\n            // Show Win Modal\n            document.querySelector(\".round-win-amount\").textContent = `+${reward.toLocaleString(\"pt-PT\").replace(/[.,\\s]/g, \" \")}`;\n            document.getElementById(\"modal-round-win\").classList.remove(\"hidden\");\n          } else {\n            playSound('lose');\n            \n            // Lift the correct cup as well to show where it was\n            const correctCup = document.getElementById(`cup-pos-${correctCupIndex}`);\n            correctCup.querySelector(\".coin-element\").classList.add(\"coin-visible\");\n            correctCup.querySelector(\".cup-wrapper\").classList.add(\"cup-lifted\");\n\n            // Show Lose Modal\n            document.querySelector(\".remaining-rounds-text\").textContent = `Ainda tens ${totalRounds - currentRound} rodadas restantes`;\n            document.getElementById(\"modal-round-lose\").classList.remove(\"hidden\");\n          }\n        }, 300);\n\n      }, 200);\n    }\n\n    function nextRound() {\n      // Hide modals\n      document.getElementById(\"modal-round-win\").classList.add(\"hidden\");\n      document.getElementById(\"modal-round-lose\").classList.add(\"hidden\");\n\n      if (currentRound < totalRounds) {\n        currentRound++;\n        resetGameRound();\n      } else {\n        // End game, go to summary\n        switchScreen('summary');\n      }\n    }\n\n\n    // ----------------- REGISTRATION FLOW LOGIC -----------------\n    let regStep = 'intro';\n    const regStepsList = ['intro', 'name', 'region', 'phone'];\n    const provinces = [\"Bengo\",\"Benguela\",\"Bié\",\"Cabinda\",\"Cuando Cubango\",\"Cuanza Norte\",\"Cuanza Sul\",\"Cunene\",\"Huambo\",\"Huíla\",\"Luanda\",\"Lunda Norte\",\"Lunda Sul\",\"Malanje\",\"Moxico\",\"Namibe\",\"Uíge\",\"Zaire\"];\n    let userData = {\n      name: '',\n      region: '',\n      phone: ''\n    };\n\n    function gotoRegistration() {\n      switchScreen('registration');\n    }\n\n    function showRegStep(step) {\n      regStep = step;\n      // Hide all sub-steps\n      document.getElementById(\"reg-step-intro\").classList.add(\"hidden\");\n      document.getElementById(\"reg-form-container\").classList.add(\"hidden\");\n      document.getElementById(\"reg-form-step-name\").classList.add(\"hidden\");\n      document.getElementById(\"reg-form-step-region\").classList.add(\"hidden\");\n      document.getElementById(\"reg-form-step-phone\").classList.add(\"hidden\");\n\n      if (step === 'intro') {\n        document.getElementById(\"reg-step-intro\").classList.remove(\"hidden\");\n      } else {\n        document.getElementById(\"reg-form-container\").classList.remove(\"hidden\");\n        document.getElementById(`reg-form-step-${step}`).classList.remove(\"hidden\");\n        \n        // Update progress dots colors\n        const stepIdx = regStepsList.indexOf(step); // name=1, region=2, phone=3\n        for (let i = 1; i <= 3; i++) {\n          const dot = document.getElementById(`reg-dot-${i}`);\n          if (i <= stepIdx) {\n            dot.className = \"w-10 h-2 rounded-full reg-dot bg-[#f59e0b]\";\n          } else {\n            dot.className = \"w-10 h-2 rounded-full reg-dot bg-[#1a2436]\";\n          }\n        }\n\n        // Update button text and state\n        const actionBtn = document.getElementById(\"btn-reg-action\");\n        if (step === 'phone') {\n          actionBtn.textContent = \"Levantar meus ganhos\";\n        } else {\n          actionBtn.textContent = \"Continuar\";\n        }\n        \n        validateCurrentStep();\n      }\n    }\n\n    function startRegFlow() {\n      showRegStep('name');\n    }\n\n    function regBack() {\n      const idx = regStepsList.indexOf(regStep);\n      if (idx > 0) {\n        showRegStep(regStepsList[idx - 1]);\n      } else {\n        switchScreen('summary');\n      }\n    }\n\n    function regNext() {\n      const idx = regStepsList.indexOf(regStep);\n      if (regStep === 'phone') {\n        // Registration complete, go to VSL\n        switchScreen('vsl');\n      } else {\n        showRegStep(regStepsList[idx + 1]);\n      }\n    }\n\n    // Input listeners for validation\n    document.getElementById(\"input-full-name\").addEventListener(\"input\", (e) => {\n      userData.name = e.target.value.trim();\n      validateCurrentStep();\n    });\n\n    document.getElementById(\"input-phone-number\").addEventListener(\"input\", (e) => {\n      userData.phone = e.target.value.trim();\n      validateCurrentStep();\n    });\n\n    function validateCurrentStep() {\n      const actionBtn = document.getElementById(\"btn-reg-action\");\n      let isValid = false;\n      \n      if (regStep === 'name') {\n        isValid = userData.name.length >= 3;\n      } else if (regStep === 'region') {\n        isValid = userData.region.length > 0;\n      } else if (regStep === 'phone') {\n        isValid = userData.phone.length >= 6; // Simple check for telemóvel\n      }\n\n      if (isValid) {\n        actionBtn.removeAttribute(\"disabled\");\n        actionBtn.className = \"w-full py-4 bg-gradient-to-r from-[#eab308] to-[#f59e0b] text-black font-bold rounded-2xl flex items-center justify-center gap-2 hover:opacity-90 transition-opacity\";\n      } else {\n        actionBtn.setAttribute(\"disabled\", \"true\");\n        actionBtn.className = \"w-full py-4 bg-[#374151] text-white font-bold rounded-2xl flex items-center justify-center gap-2 hover:bg-[#4b5563] transition-colors disabled:opacity-50 disabled:cursor-not-allowed\";\n      }\n    }\n\n    // Region Dropdown Logic\n    function toggleRegionDropdown() {\n      const list = document.getElementById(\"region-list\");\n      const arrow = document.getElementById(\"region-arrow\");\n      const isHidden = list.classList.contains(\"hidden\");\n\n      if (isHidden) {\n        list.classList.remove(\"hidden\");\n        arrow.style.transform = \"rotate(180deg)\";\n        \n        // Populate list\n        list.innerHTML = \"\";\n        provinces.forEach(p => {\n          const btn = document.createElement(\"button\");\n          btn.className = \"w-full px-6 py-3 text-left text-white hover:bg-[#2a3446] transition-colors border-b border-[#0a0f1a]/50 last:border-b-0 text-sm\";\n          btn.textContent = p;\n          btn.onclick = () => selectRegion(p);\n          list.appendChild(btn);\n        });\n      } else {\n        list.classList.add(\"hidden\");\n        arrow.style.transform = \"rotate(0deg)\";\n      }\n    }\n\n    function selectRegion(prov) {\n      userData.region = prov;\n      document.getElementById(\"selected-region-text\").textContent = prov;\n      document.getElementById(\"selected-region-text\").className = \"text-white text-sm\";\n      \n      // Close list\n      document.getElementById(\"region-list\").classList.add(\"hidden\");\n      document.getElementById(\"region-arrow\").style.transform = \"rotate(0deg)\";\n      \n      validateCurrentStep();\n    }\n\n\n    // ----------------- VSL SCREEN LOGIC -----------------\n    let liveUsers = 247;\n\n    let vslTimerStarted = false;\n    let vslTimerId = null;\n\n    function startVslTimer() {\n      if (vslTimerStarted) return;\n      vslTimerStarted = true;\n      console.log(\"VSL Timer started!\");\n\n      const delay = 240000; // 4 minutes (240k ms) for all environments\n\n      if (vslTimerId) clearTimeout(vslTimerId);\n      vslTimerId = setTimeout(() => {\n        const placeholderContainer = document.getElementById(\"vsl-placeholder-container\");\n        const bottomContent = document.getElementById(\"vsl-bottom-content\");\n\n        // After 4 minutes, the placeholder text and everything below the VSL video disappears\n        if (placeholderContainer) {\n          placeholderContainer.style.setProperty('display', 'none', 'important');\n        }\n        if (bottomContent) {\n          bottomContent.style.setProperty('display', 'none', 'important');\n        }\n        console.log(\"VSL Timer finished! Placeholder and bottom content removed.\");\n      }, delay);\n    }\n\n    function startVslFlow() {\n      // Set final winnings labels on VSL page\n      document.querySelectorAll(\".vsl-final-amount\").forEach(el => el.textContent = formatKz(balance));\n\n      // Fluctuate live audience count\n      setInterval(() => {\n        liveUsers += Math.floor(Math.random() * 5) - 2;\n        if (liveUsers < 100) liveUsers = 120;\n        document.getElementById(\"live-users-count\").textContent = liveUsers;\n      }, 4000);\n\n      // Reset visibility states on entrance (everything is visible initially)\n      vslTimerStarted = false;\n      if (vslTimerId) clearTimeout(vslTimerId);\n\n      const placeholderContainer = document.getElementById(\"vsl-placeholder-container\");\n      const bottomContent = document.getElementById(\"vsl-bottom-content\");\n\n      if (placeholderContainer) {\n        placeholderContainer.style.setProperty('display', 'block', 'important');\n      }\n      if (bottomContent) {\n        bottomContent.style.setProperty('display', 'block', 'important');\n      }\n\n      // Start the 4-minute timer immediately upon arriving at the VSL page\n      startVslTimer();\n\n      // Render comments\n      renderComments();\n    }\n\n\n\n    const commentsList = [\n      { id: 1, name: \"Maria Santos\", text: \"Acabei de receber meus 118.500 Kz! Pensei que era mentira mas funcionou mesmo. Obrigada BantuBet!\", likes: 4300, time: \"há 2 horas\", isCreator: false, avatar: \"https://hebbkx1anhila5yf.public.blob.vercel-storage.com/F-K9OTqIBgC4sRBkRffa4qDSO5FZfpYW.jpg\" },\n      { id: 2, name: \"João Pedro\", text: \"Funciona pra quem nunca usou a BantuBet antes?\", likes: 892, time: \"há 5 horas\", isCreator: false, avatar: \"https://hebbkx1anhila5yf.public.blob.vercel-storage.com/H-fjtmuZLYTqqBW5yzf9YZE11WGbh342.jpg\" },\n      { id: 3, name: \"Fly Skuad TV\", text: \"@João Pedro Sim! O evento de 5 anos é para todos, novos e antigos usuários. Só precisa criar conta e completar o perfil.\", likes: 1205, time: \"há 4 horas\", isCreator: true, avatar: \"https://hebbkx1anhila5yf.public.blob.vercel-storage.com/channels4_profile-Zn79LAkSQViJvsIAGvojP7WSIMwEvo.jpg\" },\n      { id: 4, name: \"Ana Beatriz\", text: \"Meu marido não acreditava, mostrei o comprovante e ele ficou chocado kkkk\", likes: 2100, time: \"há 1 dia\", isCreator: false, avatar: \"https://hebbkx1anhila5yf.public.blob.vercel-storage.com/F2-7HwqKfPC0qNNmSp4elv7xBjSMpSSvi.jpg\" },\n      { id: 5, name: \"Carlos Eduardo\", text: \"Já era cliente da BantuBet, esse evento de aniversário foi a melhor coisa que fizeram!\", likes: 1543, time: \"há 2 dias\", isCreator: false, avatar: \"https://hebbkx1anhila5yf.public.blob.vercel-storage.com/H2-D4rSTTHSXc8F0F2lwJ0XEbRkE799qk.jpg\" },\n      { id: 6, name: \"Fernanda Lima\", text: \"Quanto tempo demora pra cair na conta?\", likes: 456, time: \"há 3 horas\", isCreator: false, avatar: \"https://hebbkx1anhila5yf.public.blob.vercel-storage.com/F3-7zOBKrI0b56alqsFUZS78N1wuPJeF2.jpg\" },\n      { id: 7, name: \"Fly Skuad TV\", text: \"@Fernanda Lima Normalmente cai em até 24h úteis pelo Multicaixa Express. Por IBAN pode demorar 2-3 dias.\", likes: 789, time: \"há 2 horas\", isCreator: true, avatar: \"https://hebbkx1anhila5yf.public.blob.vercel-storage.com/channels4_profile-Zn79LAkSQViJvsIAGvojP7WSIMwEvo.jpg\" },\n      { id: 8, name: \"Ricardo Mendes\", text: \"Comecei ontem e já ganhei mais de 100 mil Kz no jogo dos copos. Muito fácil!\", likes: 3200, time: \"há 6 horas\", isCreator: false, avatar: \"https://hebbkx1anhila5yf.public.blob.vercel-storage.com/H3-i5nD6dSKxEjwEkY6TD0TQp4sIz3Tpc.jpg\" },\n      { id: 9, name: \"Patrícia Oliveira\", text: \"Gente, é real! Recebi hoje de manhã. Deus abençoe a BantuBet\", likes: 1876, time: \"há 1 dia\", isCreator: false, avatar: \"https://hebbkx1anhila5yf.public.blob.vercel-storage.com/F4-7yiTMqP1TXIUf0NdD8xHPqEAxcNWUZ.jpg\" },\n      { id: 10, name: \"Miguel Costa\", text: \"Precisa depositar alguma coisa antes?\", likes: 234, time: \"há 4 horas\", isCreator: false, avatar: \"https://hebbkx1anhila5yf.public.blob.vercel-storage.com/H4-Bz03Gq9YrsZcEwDbqgeAWh5VeRRhks.jpg\" },\n      { id: 11, name: \"Fly Skuad TV\", text: \"@Miguel Costa Não! O evento é 100% grátis. Você só joga as 12 rodadas e levanta os ganhos.\", likes: 567, time: \"há 3 horas\", isCreator: true, avatar: \"https://hebbkx1anhila5yf.public.blob.vercel-storage.com/channels4_profile-Zn79LAkSQViJvsIAGvojP7WSIMwEvo.jpg\" },\n      { id: 12, name: \"Juliana Ferreira\", text: \"Melhor promoção que já vi em Angola. 5 anos de BantuBet e muitos mais!\", likes: 2890, time: \"há 2 dias\", isCreator: false, avatar: \"https://hebbkx1anhila5yf.public.blob.vercel-storage.com/F-K9OTqIBgC4sRBkRffa4qDSO5FZfpYW.jpg\" }\n    ];\n\n    function renderComments() {\n      const container = document.getElementById(\"vsl-comments-list\");\n      container.innerHTML = \"\";\n      commentsList.forEach(c => {\n        const item = document.createElement(\"div\");\n        item.className = \"flex gap-3 sm:gap-4 text-left\";\n        item.innerHTML = `\n          <img src=\"${c.avatar}\" alt=\"${c.name}\" class=\"w-9 h-9 sm:w-10 sm:h-10 rounded-full object-cover flex-shrink-0\">\n          <div class=\"flex-1 min-w-0\">\n            <div class=\"flex flex-wrap items-center gap-x-2 gap-y-0.5 mb-1\">\n              <span class=\"font-medium text-xs sm:text-sm text-white\">${c.name}</span>\n              ${c.isCreator ? '<span class=\"bg-[#303030] text-gray-300 text-xs px-2 py-0.5 rounded\">Criador</span>' : ''}\n              <span class=\"text-gray-400 text-xs\">${c.time}</span>\n            </div>\n            <p class=\"text-sm mb-2 break-words text-gray-200\">${c.text}</p>\n            <div class=\"flex items-center gap-4 text-gray-400\">\n              <button onclick=\"likeComment(${c.id})\" class=\"flex items-center gap-1 text-sm hover:text-white\" id=\"like-btn-${c.id}\">\n                <svg class=\"w-4 h-4\" fill=\"currentColor\" viewBox=\"0 0 24 24\"><path d=\"M1 21h4V9H1v12zm22-11c0-1.1-.9-2-2-2h-6.31l.95-4.57.03-.32c0-.41-.17-.79-.44-1.06L14.17 1 7.59 7.59C7.22 7.95 7 8.45 7 9v10c0 1.1.9 2 2 2h9c.83 0 1.54-.5 1.84-1.22l3.02-7.05c.09-.23.14-.47.14-.73v-2z\"></path></svg>\n                <span class=\"likes-count\" id=\"likes-count-${c.id}\">${c.likes.toLocaleString(\"pt-PT\")}</span>\n              </button>\n              <button class=\"hover:text-white\">\n                <svg class=\"w-4 h-4 rotate-180\" fill=\"currentColor\" viewBox=\"0 0 24 24\"><path d=\"M1 21h4V9H1v12zm22-11c0-1.1-.9-2-2-2h-6.31l.95-4.57.03-.32c0-.41-.17-.79-.44-1.06L14.17 1 7.59 7.59C7.22 7.95 7 8.45 7 9v10c0 1.1.9 2 2 2h9c.83 0 1.54-.5 1.84-1.22l3.02-7.05c.09-.23.14-.47.14-.73v-2z\"></path></svg>\n              </button>\n              <button class=\"text-sm hover:text-white\">Responder</button>\n            </div>\n          </div>\n        `;\n        container.appendChild(item);\n      });\n    }\n\n    const likedComments = new Set();\n    function likeComment(commentId) {\n      if (likedComments.has(commentId)) return;\n      likedComments.add(commentId);\n      const c = commentsList.find(item => item.id === commentId);\n      if (c) {\n        c.likes += 1;\n        document.getElementById(`likes-count-${commentId}`).textContent = c.likes.toLocaleString(\"pt-PT\");\n        document.getElementById(`like-btn-${commentId}`).classList.add(\"text-blue-400\");\n      }\n    }\n\n    function triggerConfetti() {\n      const colors = [\"#f97316\", \"#22c55e\", \"#3b82f6\", \"#f59e0b\", \"#ef4444\", \"#fbbf24\", \"#fb923c\", \"#4ade80\"];\n      const shapes = [\"square\", \"rect\", \"circle\"];\n      \n      const count = 60;\n      for (let i = 0; i < count; i++) {\n        const piece = document.createElement(\"div\");\n        piece.className = \"confetti-piece\";\n        \n        const shape = shapes[Math.floor(Math.random() * shapes.length)];\n        const color = colors[Math.floor(Math.random() * colors.length)];\n        const left = Math.random() * 100;\n        const delay = Math.random() * 1.5;\n        const duration = 2.5 + Math.random() * 2;\n        const w = shape === 'rect' ? 4 + Math.random() * 4 : 6 + Math.random() * 8;\n        const h = shape === 'rect' ? 10 + Math.random() * 8 : 6 + Math.random() * 8;\n        \n        piece.style.left = `${left}%`;\n        piece.style.backgroundColor = color;\n        piece.style.width = `${w}px`;\n        piece.style.height = `${h}px`;\n        piece.style.animationDelay = `${delay}s`;\n        piece.style.animationDuration = `${duration}s`;\n        if (shape === 'circle') {\n          piece.style.borderRadius = \"50%\";\n        } else if (shape === 'rect' || shape === 'square') {\n          piece.style.borderRadius = \"2px\";\n        }\n        \n        document.body.appendChild(piece);\n        \n        // Remove after animation finishes\n        setTimeout(() => {\n          piece.remove();\n        }, (delay + duration) * 1000);\n      }\n    }\n\ndocument.addEventListener(\"contextmenu\", e => {\n    e.preventDefault();\n});\n\n";

  res.status(200).json({ html, scripts });
